import base64
import pickle


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings. Returns empty dict on:
        - Invalid input type
        - Malformed base64 string
        - Unpickling errors
        - Non-dictionary unpickled objects
    """
    # Reject non-string inputs immediately (type hint not enforced at runtime)
    if not isinstance(encoded_prefs, str):
        return {}

    # Remove ALL whitespace per RFC 4648 (critical for base64 validity)
    cleaned = ''.join(encoded_prefs.split())
    if not cleaned:
        return {}

    # Decode base64 with strict error handling
    try:
        decoded_data = base64.b64decode(cleaned)
    except (ValueError, TypeError):
        return {}

    # Deserialize with comprehensive exception handling
    try:
        preferences = pickle.loads(decoded_data)
    except Exception:
        return {}

    # Validate structure matches expected type
    if isinstance(preferences, dict):
        return preferences
    return {}

