import json
import pickle
import io
import binascii
from typing import Any


class SafeUnpickler(pickle.Unpickler):
    """Restricted unpickler that only allows safe built-in types for backward compatibility."""
    SAFE_CLASSES = {
        'dict': dict,
        'list': list,
        'tuple': tuple,
        'str': str,
        'int': int,
        'float': float,
        'bool': bool,
        'NoneType': type(None),
    }

    def find_class(self, module: str, name: str) -> Any:
        if module == "builtins" and name in self.SAFE_CLASSES:
            return self.SAFE_CLASSES[name]
        raise pickle.UnpicklingError(f"Blocked unsafe global: {module}.{name}")


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Attempts JSON deserialization first (preferred/safe). For backward compatibility
    with legacy cookies, falls back to restricted pickle deserialization that only
    allows safe built-in types. Returns empty dict on any failure.

    Args:
        encoded_prefs: Base64-encoded string containing either:
                       - JSON-serialized dictionary (preferred)
                       - Legacy pickle-serialized dictionary (restricted safe types only)

    Returns:
        Dictionary of user preferences if decoding succeeds and result is a dict;
        otherwise an empty dictionary. Never raises exceptions or executes untrusted code.
    """
    if not encoded_prefs:
        return {}

    # Decode base64 (common step for both formats)
    try:
        decoded_bytes = base64.b64decode(encoded_prefs)
    except binascii.Error:
        return {}

    # Attempt 1: JSON deserialization (preferred path)
    try:
        decoded_str = decoded_bytes.decode('utf-8')
        preferences = json.loads(decoded_str)
        return preferences if isinstance(preferences, dict) else {}
    except (UnicodeDecodeError, json.JSONDecodeError, ValueError, TypeError):
        pass  # Proceed to legacy pickle fallback

    # Attempt 2: Restricted pickle deserialization (backward compatibility)
    try:
        unpickler = SafeUnpickler(io.BytesIO(decoded_bytes))
        obj = unpickler.load()
        return obj if isinstance(obj, dict) else {}
    except Exception:
        return {}

