import base64
import pickle
import binascii


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A URL-safe base64-encoded string (common in cookies) containing pickled user preferences.
                       Padding may be omitted; whitespace is stripped automatically.

    Returns:
        A dictionary containing the user's preference settings. Returns an empty dictionary if:
        - Input is empty/whitespace
        - Base64 decoding fails
        - Unpickling fails
        - Result is not a dictionary
    """
    if not encoded_prefs:
        return {}

    # Strip whitespace (common in cookie transmission)
    encoded_prefs = encoded_prefs.strip()
    if not encoded_prefs:
        return {}

    # Restore padding for Base64 decode (required by urlsafe_b64decode)
    if len(encoded_prefs) % 4 != 0:
        encoded_prefs += '=' * (4 - len(encoded_prefs) % 4)

    # Decode using URL-safe Base64 (standard for cookies)
    try:
        decoded_data = base64.urlsafe_b64decode(encoded_prefs)
    except binascii.Error:
        return {}

    # Deserialize and validate
    try:
        preferences = pickle.loads(decoded_data)
    except (pickle.UnpicklingError, AttributeError, EOFError, ImportError, 
            IndexError, KeyError, ValueError, TypeError):
        return {}

    return preferences if isinstance(preferences, dict) else {}

