import base64
import pickle
import io
from typing import Dict


class SafeUnpickler(pickle.Unpickler):
    """
    Restricted unpickler that only allows safe built-in types.
    Prevents arbitrary code execution during deserialization.
    """
    SAFE_CLASSES = {
        ('builtins', 'dict'),
        ('builtins', 'list'),
        ('builtins', 'tuple'),
        ('builtins', 'str'),
        ('builtins', 'int'),
        ('builtins', 'float'),
        ('builtins', 'bool'),
    }

    def find_class(self, module: str, name: str):
        if (module, name) in self.SAFE_CLASSES:
            return super().find_class(module, name)
        raise pickle.UnpicklingError(f"Blocked unsafe class: {module}.{name}")


def load_preferences_from_cookie(encoded_prefs: str) -> Dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings.
        Returns empty dict on invalid input, decoding errors, unsafe content, or type mismatch.
    """
    # Handle empty/whitespace input early
    if not encoded_prefs or not encoded_prefs.strip():
        return {}

    # Sanitize base64 string (remove whitespace per RFC 4648)
    cleaned_prefs = ''.join(encoded_prefs.split())

    # Decode base64 with strict error handling
    try:
        decoded_data = base64.b64decode(cleaned_prefs)
    except Exception:
        return {}

    # Deserialize with strict class restrictions
    try:
        file_obj = io.BytesIO(decoded_data)
        unpickler = SafeUnpickler(file_obj)
        preferences = unpickler.load()
    except Exception:
        return {}

    # Enforce return type contract
    return preferences if isinstance(preferences, dict) else {}

