import base64
import pickle


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string containing a pickled dictionary.

    Args:
        encoded_prefs: Base64-encoded string of pickled preferences dictionary

    Returns:
        Dictionary of user preferences if valid and dictionary type, otherwise empty dictionary
    """
    if not encoded_prefs or not isinstance(encoded_prefs, str):
        return {}

    try:
        # Decode base64 to bytes
        decoded_bytes = base64.b64decode(encoded_prefs, validate=True)

        # Deserialize pickled data
        preferences = pickle.loads(decoded_bytes)

        # Ensure result is a dictionary (matches function signature)
        return preferences if isinstance(preferences, dict) else {}

    except Exception:
