    padded = encoded_prefs.strip() + '=' * (-len(encoded_prefs.strip()) % 4)

    try:
        # Decode URL-safe Base64 (standard for web cookies)
        decoded_bytes = base64.urlsafe_b64decode(padded)
    except (ValueError, TypeError, binascii.Error):
        return {}

    try:
        # Deserialize using restricted unpickler
        obj = SafeUnpickler(BytesIO(decoded_bytes)).load()
    except (pickle.UnpicklingError, AttributeError, EOFError, 
            ImportError, IndexError, KeyError, ValueError, 
            MemoryError, RecursionError):
        return {}

    # Strict type validation: only accept dictionary objects
    return obj if isinstance(obj, dict) else {}

